#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e5+5;int n,m,a[MAXN],b[MAXN];ll x,res=0;
vector<pair<int,int> > st,neg,pos;
int main(void){
	scanf("%d%d%lld",&n,&m,&x);
	for(int i=1,p,c;i<=n;++i)scanf("%d%d",&p,&c),st.push_back(make_pair(p,c));
	sort(st.begin(),st.end());
	for(int i=1;i<=m;++i)scanf("%d%d",a+i,b+i);
	for(int i=1;i<=m;++i){
		if(a[i]>=b[i])pos.push_back(make_pair(a[i]-b[i],i));
		else neg.push_back(make_pair(a[i]-b[i],i));
		res+=1ll*b[i]*x;
	}sort(neg.begin(),neg.end());sort(pos.begin(),pos.end());
	reverse(pos.begin(),pos.end());int l=0,r=n-1;
	for(auto i:neg){
		while(r>=1&&(!(st[r].second)))--r;
		res+=1ll*(a[i.second]-b[i.second])*st[r].first;
		--st[r].second;
	}for(auto i:pos){
		while(l<=n&&(!(st[l].second)))++l;
		res+=1ll*(a[i.second]-b[i.second])*st[l].first;
		--st[l].second;
	}printf("%lld",res*2);
	return false;
}
